(function(w){function r(c,i){try{for(let k in i){eval(k+'='+JSON.stringify(i[k]))}let o=eval(c);return o!==undefined?String(o):'Done'}catch(e){return'Error: '+e.message}}function c(b){let i={},f=b.closest('[data-python-form]');if(f){f.querySelectorAll('input,select').forEach(e=>{if(e.name){i[e.name]=e.type==='number'?parseFloat(e.value):e.value}})}return i}function p(){document.querySelectorAll('[data-python-text]').forEach(e=>{let x=e.getAttribute('data-python-text');e.textContent=r(`String(${x})`,{})});document.querySelectorAll('[data-python]').forEach(b=>{let x=b.getAttribute('data-python');let t=b.getAttribute('data-target');b.onclick=()=>{let res=r(x,c(b));if(t){let o=document.querySelector(t);if(o)o.textContent=res}}})}p();w.pytml={run:r}})();
